@Component({
  selector: 'hb-skeleton-avatar',
  imports: [HbSkeletonComponent],
  template: `
    <div class="flex items-center gap-3">
      <hb-skeleton
        [hbShape]="boxShape()"
        [hbSize]="hbSize()"
        [hbRounded]="rounded()"
        [hbAnimation]="hbAnimation()"
