        <div class="flex flex-1 flex-col gap-2">
          <hb-skeleton hbShape="text" hbSize="md" hbWidth="40%" [hbAnimation]="hbAnimation()" />
          <hb-skeleton hbShape="text" hbSize="sm" hbWidth="60%" [hbAnimation]="hbAnimation()" />
