import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  ViewEncapsulation,
} from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import {
  skeletonVariants,
  SKELETON_BOX_SIZE,
  SKELETON_ROUNDED,
  SKELETON_TEXT_SIZE,
  type HbSkeletonAnimation,
  type HbSkeletonRounded,
  type HbSkeletonShape,
  type HbSkeletonSize,
} from './skeleton.variants';

@Component({
  selector: 'hb-skeleton',
  template: '',
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  styles: `
    .hb-skeleton-wave::after {
      content: '';
      position: absolute;
      inset: 0;
      transform: translateX(-100%);
      background: linear-gradient(
        90deg,
        transparent,
        color-mix(in oklab, currentColor 8%, transparent),
        transparent
      );
      animation: hb-skeleton-wave 1.6s ease-in-out infinite;
    }
    @keyframes hb-skeleton-wave {
      100% {
        transform: translateX(100%);
      }
    }
  `,
  host: {
    '[class]': 'classes()',
    '[style.width]': 'hbWidth() || null',
    '[style.height]': 'hbHeight() || null',
    '[attr.data-slot]': "'skeleton'",
    '[attr.data-shape]': 'hbShape()',
    'aria-hidden': 'true',
  },
  exportAs: 'hbSkeleton',
})
export class HbSkeletonComponent {
  readonly hbShape = input<HbSkeletonShape>('rectangle');
  readonly hbSize = input<HbSkeletonSize>('md');
  readonly hbWidth = input<string>('');
  readonly hbHeight = input<string>('');
  readonly hbRounded = input<HbSkeletonRounded>();
  readonly hbAnimation = input<HbSkeletonAnimation>('pulse');
  readonly class = input<ClassValue>('');

  protected readonly classes = computed(() => {
    const shape = this.hbShape();
    const hasExplicitSize = !!this.hbWidth() || !!this.hbHeight();
    let dims = '';
    if (shape === 'circle' || shape === 'square') {
      dims = hasExplicitSize ? '' : SKELETON_BOX_SIZE[this.hbSize()];
    } else if (shape === 'text') {
      dims = SKELETON_TEXT_SIZE[this.hbSize()];
    } else {
      dims = this.hbHeight() ? '' : 'h-4';
    }
    const rounded = this.hbRounded() ? SKELETON_ROUNDED[this.hbRounded()!] : '';
    return cn(
      skeletonVariants({ animation: this.hbAnimation(), shape }),
      dims,
      rounded,
      this.class(),
    );
  });
}

import { HbSkeletonAvatarComponent } from './skeleton-avatar.component';
import { HbSkeletonButtonComponent } from './skeleton-button.component';
import { HbSkeletonCardComponent } from './skeleton-card.component';
import { HbSkeletonFormComponent } from './skeleton-form.component';
import { HbSkeletonInputComponent } from './skeleton-input.component';
import { HbSkeletonListComponent } from './skeleton-list.component';
import { HbSkeletonTableComponent } from './skeleton-table.component';
import { HbSkeletonTextComponent } from './skeleton-text.component';
import { HbSkeletonComponent } from './skeleton.component';

export const HbSkeletonImports = [
  HbSkeletonComponent,
  HbSkeletonTextComponent,
  HbSkeletonButtonComponent,
  HbSkeletonInputComponent,
  HbSkeletonAvatarComponent,
  HbSkeletonCardComponent,
  HbSkeletonListComponent,
  HbSkeletonFormComponent,
  HbSkeletonTableComponent,
] as const;

import { cva, type VariantProps } from 'class-variance-authority';

export const skeletonVariants = cva('block shrink-0 bg-accent', {
  variants: {
    animation: {
      pulse: 'animate-pulse',
      wave: 'hb-skeleton-wave relative overflow-hidden',
      none: '',
    },
    shape: {
      rectangle: 'w-full rounded-md',
      circle: 'aspect-square rounded-full',
      square: 'aspect-square rounded-md',
      text: 'w-full rounded',
    },
  },
  defaultVariants: { animation: 'pulse', shape: 'rectangle' },
});

export type HbSkeletonSize = 'xs' | 'sm' | 'md' | 'lg' | 'xl';
export type HbSkeletonShape = NonNullable<VariantProps<typeof skeletonVariants>['shape']>;
export type HbSkeletonAnimation = NonNullable<VariantProps<typeof skeletonVariants>['animation']>;
export type HbSkeletonRounded = 'none' | 'sm' | 'md' | 'lg' | 'full';
export type HbSkeletonAvatarShape = 'circle' | 'square' | 'rounded';

export const SKELETON_BOX_SIZE: Record<HbSkeletonSize, string> = {
  xs: 'size-6',
  sm: 'size-8',
  md: 'size-10',
  lg: 'size-12',
  xl: 'size-16',
};

export const SKELETON_TEXT_SIZE: Record<HbSkeletonSize, string> = {
  xs: 'h-2',
  sm: 'h-2.5',
  md: 'h-3.5',
  lg: 'h-4',
  xl: 'h-5',
};

export const SKELETON_CONTROL_HEIGHT: Record<HbSkeletonSize, string> = {
  xs: '1.75rem',
  sm: '2rem',
  md: '2.25rem',
  lg: '2.5rem',
  xl: '2.75rem',
};

export const SKELETON_ROUNDED: Record<HbSkeletonRounded, string> = {
  none: 'rounded-none',
  sm: 'rounded-sm',
  md: 'rounded-md',
  lg: 'rounded-lg',
  full: 'rounded-full',
};

